// Cache-aside pattern
async function getUser(userId) {
  const cacheKey = `user:${userId}`;
  let user = await redis.get(cacheKey);

  if (!user) {
    user = await db.users.findById(userId);
    await redis.setex(cacheKey, 300, JSON.stringify(user));
  } else {
    user = JSON.parse(user);
  }

  return user;
}
